		Title: "Code Review Findings",
	})
	if err != nil {
		t.Fatalf("Second inject: %v", err)
	}
	if reviewID2 != reviewID {
		t.Errorf("expected idempotent ID %s, got %s", reviewID, reviewID2)
	}

