		ProjectRoot: projectRoot,
		TempRoot:    tempRoot,
		EvidenceRoots: []string{
			filepath.Join(projectRoot, ddxroot.DirName, "executions"),
		},
		CleanupRunner: cleanup,
		RootProbe: func(path string) (agent.ExecutionResourceRootCheck, error) {
