func TestStoreRejectsInvalidStatus(t *testing.T) {
	store := newTestStore(t)
	b := &Bead{Title: "bad status", IssueType: "task", Priority: 2, Status: "weird"}
	err := store.Create(context.Background(), testCtx(), b)
